INSERT OR IGNORE INTO conditions (id,name,system_id,overview,icd10_code,slug) VALUES
  ('dengue','Dengue Fever','infectious','Dengue is a mosquito-borne viral infection caused by the dengue virus (DENV 1-4) transmitted by Aedes aegypti. It ranges from mild febrile illness to severe dengue with plasma leakage, hemorrhage, and organ impairment. Bangladesh sees seasonal outbreaks, primarily June–October.','A90','dengue'),
  ('typhoid','Typhoid Fever','infectious','Typhoid fever is a systemic infection caused by Salmonella enterica serovar Typhi. Transmitted via contaminated food and water. Endemic in Bangladesh. Presents with stepwise fever, relative bradycardia, rose spots, and abdominal symptoms.','A01.0','typhoid'),
  ('malaria','Malaria','infectious','Malaria is caused by Plasmodium parasites (P. falciparum 68%, P. vivax 32% in BD) transmitted by Anopheles mosquitoes. Endemic in Chittagong Hill Tracts. P. falciparum can cause severe/cerebral malaria.','B54','malaria'),
  ('pneumonia','Community-Acquired Pneumonia','respiratory','CAP is an acute infection of the pulmonary parenchyma acquired outside hospital. Common pathogens: Streptococcus pneumoniae, Haemophilus influenzae, atypical organisms. CURB-65 score guides admission decision.','J18.9','pneumonia'),
  ('acs','Acute Coronary Syndrome','cardiology','ACS encompasses STEMI, NSTEMI, and unstable angina. Caused by rupture of atherosclerotic plaque with thrombosis. Time-critical: door-to-needle < 30 min for thrombolysis, door-to-balloon < 90 min for PCI.','I24.9','acs'),
  ('dka','Diabetic Ketoacidosis','endocrine','DKA is a life-threatening complication of diabetes with hyperglycemia, metabolic acidosis, and ketosis. Precipitated by infection, missed insulin, or new-onset T1DM. Treatment: fluid, insulin, electrolyte replacement.','E10.1','dka'),
  ('uti','Urinary Tract Infection','nephrology','UTI includes cystitis (lower) and pyelonephritis (upper). Commonest organism: E. coli. Women more affected. Uncomplicated cystitis treated empirically; pyelonephritis requires urine culture and longer course.','N39.0','uti'),
  ('stroke','Ischaemic Stroke','neurology','Ischaemic stroke is caused by cerebral artery occlusion. FAST acronym: Face drooping, Arm weakness, Speech difficulty, Time to call. Thrombolysis (rtPA) within 4.5 hours if eligible. CT head to exclude haemorrhage first.','I63.9','stroke'),
  ('anaemia','Iron Deficiency Anaemia','haematology','IDA is the commonest cause of anaemia worldwide. In Bangladesh, nutritional deficiency and helminth infection are major causes. Presents with fatigue, pallor, koilonychia, angular stomatitis.','D50.9','anaemia'),
  ('cholera','Cholera','infectious','Cholera is caused by Vibrio cholerae O1/O139. Presents with sudden-onset watery diarrhoea (''rice-water stool''), vomiting, and rapid dehydration. Can be fatal within hours if untreated. Oral or IV rehydration is the cornerstone of treatment.','A00.9','cholera');
