INSERT OR IGNORE INTO protocol_steps (protocol_id,step_number,heading,body,sub_steps_json,table_json,severity) VALUES
  ('1','1','Step 1: Classify the Patient','Use the DGHS 3-group classification based on warning signs and severity:','["GROUP A (Mild) — No warning signs, tolerating oral fluids, normal urine output → SEND HOME","GROUP B (Moderate) — Any warning sign present, OR high-risk patient (infant, pregnancy, DM, renal disease, haematological condition) → ADMIT for monitoring","GROUP C (Severe) — Severe plasma leakage with shock (DSS), severe haemorrhage, severe organ impairment → EMERGENCY MANAGEMENT"]',NULL,'all'),
  ('1','2','Step 2: Warning Signs to Watch','Any ONE of these = Group B (admit immediately):','["Severe abdominal pain or tenderness","Persistent vomiting (>3 times/day)","Clinical fluid accumulation (ascites, pleural effusion)","Mucosal bleeding (haematemesis, melaena)","Lethargy, restlessness, or sudden behavioural change","Liver enlargement >2 cm","Tourniquet test positive (≥20 petechiae per 2.5 cm²)","Rapid drop in platelet AND concurrent rise in haematocrit"]',NULL,'group-b'),
  ('1','3','Step 3: Group A — Home Management','Adequate rest and oral fluid intake. Return immediately if warning signs develop.','["Paracetamol 500–1000 mg every 6 hours for fever (MAX 4g/day) — NOT aspirin or ibuprofen (risk of bleeding)","Oral fluids: 2–3 litres/day — ORS, coconut water, fruit juice, rice water","Monitor: temperature, fluid intake/output, urine output","Return immediately if: no improvement after 48h, warning signs develop, unable to tolerate oral fluids","Follow-up in 24–48 hours"]',NULL,'group-a'),
  ('1','4','Step 4: Group B — In-Hospital Management','Admit, IV access, baseline investigations, fluid management protocol.','["IV access + blood: CBC (platelets, Hct), LFT (AST/ALT), blood group, NS1 antigen / IgM-IgG serology","Encourage oral fluids. If not tolerated: IV fluids — NS or Ringer''s Lactate","Fluid rate: maintenance + 5% deficit correction based on weight","Paracetamol for fever — avoid NSAIDs","Monitor: vital signs every 4h, Hct every 12h, platelet count daily","Watch for warning signs and transition to Group C if deterioration","Discharge criteria: afebrile >48h, improving, platelets >50,000, stable haematocrit, adequate urine output"]',NULL,'group-b'),
  ('1','5','Step 5: Group C — Emergency Management (DSS)','Dengue Shock Syndrome — immediate aggressive IV fluid resuscitation.','["IMMEDIATE: IV NS or RL 10–20 ml/kg over 1 hour","Reassess: if improved → reduce to 5–7 ml/kg/hr for 1–2h, then 3–5 ml/kg/hr, then 2–3 ml/kg/hr","If NOT improved after initial bolus → repeat 10–20 ml/kg bolus (maximum 2 boluses)","If still no improvement → consider colloid (Dextran 40 or fresh frozen plasma 10 ml/kg)","Severe haemorrhage: Packed Red Cells or Fresh Whole Blood (10 ml/kg)","Severe thrombocytopenia with bleeding: Platelet concentrate (if platelets <10,000 or <20,000 with active bleed)","ICU transfer: persistent shock despite 2 fluid boluses, severe organ impairment, severe haemorrhage"]','{"title":"Fluid Rate Guide","headers":["Phase","Rate"],"rows":[["Initial bolus (shock)","10–20 ml/kg/hr × 1 hr"],["Step down 1","5–7 ml/kg/hr × 1–2 hr"],["Step down 2","3–5 ml/kg/hr × 2–4 hr"],["Step down 3","2–3 ml/kg/hr × 2–4 hr"],["Maintenance","1–2 ml/kg/hr, monitor Hct"]]}','group-c'),
  ('1','6','Step 6: Key Lab Thresholds','Monitor these values closely during hospitalisation:',NULL,'{"title":"Lab Monitoring","headers":["Test","Threshold","Action"],"rows":[["Haematocrit (Hct)","Rise >20% from baseline","Suspect plasma leakage → increase fluids"],["Platelet","<100,000","Increase monitoring frequency"],["Platelet","<20,000","Consider prophylactic transfusion if bleeding"],["Platelet","<10,000","Platelet transfusion regardless"],["AST or ALT","≥1000 U/L","Severe liver involvement → Group C"],["Urine output","<0.5 ml/kg/hr for >4h","Inadequate → increase fluids"]]}','all'),
  ('2','1','Step 1: Diagnosis','Clinical diagnosis + supportive lab findings. Blood culture is the gold standard.','["Blood culture (sensitivity 60–80% in week 1) — collect BEFORE starting antibiotics","Widal test: single titre O ≥1:160 or H ≥1:160 — suggestive but not diagnostic","CBC: leucopenia (WBC 2000–4000), relative lymphocytosis","LFT: mild transaminase elevation common","Stool culture (week 2–3), urine culture (week 2–4)"]',NULL,'all'),
  ('2','2','Step 2: Antibiotic Therapy','Choose based on local resistance patterns. Fluoroquinolone resistance is rising in BD.','["FIRST LINE (uncomplicated): Azithromycin 1g stat then 500mg OD × 6 days","ALTERNATIVE 1: Ceftriaxone 2g IV OD × 10–14 days (if severely ill or unable to take oral)","ALTERNATIVE 2: Cefixime 200mg BD PO × 14 days","AVOID: Fluoroquinolones (ciprofloxacin) — high resistance in BD","AVOID: Chloramphenicol, cotrimoxazole — widespread resistance","For complications (perforation, haemorrhage): IV Ceftriaxone + Metronidazole, surgical consult"]',NULL,'all'),
  ('2','3','Step 3: Supportive Care','Fever management, nutrition, hydration, monitoring for complications.','["Paracetamol for fever — tepid sponging","Soft diet, adequate hydration","Watch for: intestinal perforation (sudden worsening abdominal pain, rigidity, fever spike), GI bleeding","Dexamethasone 3 mg/kg IV then 1 mg/kg every 6h × 48h for severe typhoid with altered consciousness/shock","Isolation precautions: enteric precautions, hand hygiene"]',NULL,'all'),
  ('3','1','Step 1: Severity Assessment (CURB-65)','Score 1 point each: Confusion, Urea >7 mmol/L, RR ≥30, BP <90/60, Age ≥65.',NULL,'{"title":"CURB-65 Management","headers":["Score","Severity","Management"],"rows":[["0–1","Low","Outpatient oral antibiotics"],["2","Moderate","Consider hospitalisation"],["3–5","High","Hospital admission, consider ICU"]]}','all'),
  ('3','2','Step 2: Antibiotic Selection','Empirical antibiotics within 4 hours of diagnosis.','["OUTPATIENT (CURB-65 0-1): Amoxicillin 500mg TDS × 5 days, OR Azithromycin 500mg OD × 5 days","INPATIENT (CURB-65 2): Amoxicillin-Clavulanate 1.2g IV TDS + Azithromycin 500mg OD","SEVERE (CURB-65 3+): Ceftriaxone 2g IV OD + Azithromycin 500mg IV OD","ASPIRATION: Add Metronidazole 500mg TDS","De-escalate to oral when afebrile >48h and improving"]',NULL,'all'),
  ('3','3','Step 3: Oxygen & Supportive Care','Target SpO2 ≥94% (88–92% if COPD). IV fluids for dehydration.','["Supplemental oxygen via nasal cannula or face mask to maintain SpO2 ≥94%","High-flow oxygen or NIV if SpO2 <90% despite standard oxygen","Adequate IV fluids","Chest physiotherapy","Follow-up CXR at 6 weeks to confirm resolution"]',NULL,'all'),
  ('4','1','Step 1: Assess Dehydration','Classify dehydration severity immediately.',NULL,'{"title":"Dehydration Classification","headers":["Feature","None","Some","Severe"],"rows":[["General","Well","Restless","Lethargic/unconscious"],["Eyes","Normal","Sunken","Very sunken"],["Thirst","Drinks normally","Drinks eagerly","Unable to drink"],["Skin pinch","Returns quickly","Returns slowly","Returns very slowly"],["Management","ORS at home","ORS in clinic (Plan B)","IV Ringer''s Lactate (Plan C)"]]}','all'),
  ('4','2','Step 2: Rehydration (Plan C — Severe)','IV Ringer''s Lactate (preferred over NS for cholera).','["Adults: 100 ml/kg RL in 3 hours. First 30 ml/kg in 30 minutes.","Children <5 yrs: 100 ml/kg RL in 3 hours. First 30 ml/kg in 1 hour.","Reassess every 30 min. If improving, continue. If not, increase speed.","Once able to drink: switch to ORS, continue until diarrhoea stops"]',NULL,'severe'),
  ('4','3','Step 3: Antibiotic Therapy','Single dose antibiotic reduces severity and excretion.','["Adults: Azithromycin 1g single dose (drug of choice in BD)","Children: Azithromycin 20 mg/kg single dose (max 1g)","Alternative: Doxycycline 300mg single dose (adults only, NOT in children/pregnancy)","Tetracycline resistance is widespread — avoid"]',NULL,'all'),
  ('5','1','Step 1: Diagnosis','Confirm with RDT or microscopy before treatment. Never treat empirically.','["RDT (Rapid Diagnostic Test) — preferred for field settings","Thick and thin blood smear microscopy — gold standard, identifies species","If P. falciparum: classify as uncomplicated or severe","Severe malaria criteria: coma/impaired consciousness, severe anaemia (Hb <7), respiratory distress, repeated convulsions, inability to stand/walk, jaundice, haemoglobinuria, shock"]',NULL,'all'),
  ('5','2','Step 2: Uncomplicated P. falciparum','Artemisinin-based combination therapy (ACT) — first line.','["FIRST LINE: Artemether-Lumefantrine (Coartem) — 1.5/9 mg/kg BD × 3 days with fatty food","ALTERNATIVE: Artesunate-Amodiaquine × 3 days","Do NOT use monotherapy","Follow-up blood smear on day 3, 7, 28"]',NULL,'uncomplicated'),
  ('5','3','Step 3: Severe P. falciparum','IV Artesunate — refer to tertiary hospital.','["IV Artesunate 2.4 mg/kg at 0, 12, 24 hours, then daily","Switch to oral ACT when able to tolerate oral medications","Quinine IV if artesunate unavailable: loading dose 20 mg/kg over 4h, then 10 mg/kg every 8h","Supportive: IV fluids (cautious — avoid overhydration), monitor blood glucose, treat hypoglycaemia"]',NULL,'severe'),
  ('5','4','Step 4: P. vivax','Chloroquine + Primaquine (check G6PD first).','["Chloroquine 10 mg base/kg on day 1 and 2, then 5 mg/kg on day 3","Primaquine 0.25 mg/kg OD × 14 days (radical cure, prevents relapse)","CHECK G6PD status before primaquine — haemolysis risk in G6PD deficiency"]',NULL,'vivax');
INSERT OR IGNORE INTO er_drugs (name,indication,dose_per_kg,max_dose_mg,route,concentration_mg_per_ml,dilution_notes,warning_note,is_paediatric_safe,order_index) VALUES
  ('Adrenaline (Epinephrine)','Anaphylaxis / Cardiac Arrest','0.01','0.5','IM (lateral thigh)','1','1:1000 solution (1 mg/mL). Give IM, not IV for anaphylaxis.','IV route only for cardiac arrest. Repeat IM dose every 5–15 min if no response.','1','1'),
  ('Diazepam','Seizure / Status Epilepticus','0.3','10','IV (slow) / PR','5','IV: 5 mg/mL. Give slowly over 3 min. PR: same dose.','Monitor respiratory rate. Respiratory depression risk. Have bag-mask ready.','1','2'),
  ('Phenobarbitone','Status Epilepticus (2nd line)','20','1000','IV slow','200','200 mg/mL. Dilute to 20 mg/mL with WFI. Give at max 100 mg/min.','Causes respiratory depression and hypotension. Monitor closely.','1','3'),
  ('Hydrocortisone','Anaphylaxis / Adrenal Crisis / Severe Asthma','4','200','IV','50','100 mg/2 mL. Dilute in 10 mL NS. Give over 5–10 min.','Slow onset (hours). Not a first-line drug for anaphylaxis — use adrenaline first.','1','4'),
  ('Salbutamol (Nebulised)','Acute Severe Asthma / Bronchospasm','0.15','5','Nebulised','5','0.15 mg/kg in 2.5 mL NS via nebuliser. Repeat every 20 min × 3.','Monitor heart rate. Can cause tachycardia and hypokalaemia.','1','5'),
  ('Dextrose 10%','Hypoglycaemia','5',NULL,'IV','100','5 ml/kg of 10% Dextrose IV. (= 0.5 g/kg glucose). Target BGL >4 mmol/L.','Use 10% in children (NOT 50% — too hypertonic). Recheck BGL 15 min after.','1','6'),
  ('Atropine','Bradycardia / Organophosphate Poisoning','0.02','0.5','IV','0.6','0.6 mg/mL ampoule. Minimum dose 0.1 mg (avoid paradoxical bradycardia).','In organophosphate poisoning: large doses may be needed (2–4 mg adults). Repeat every 10 min until secretions dry.','1','7'),
  ('Adenosine','SVT (Supraventricular Tachycardia)','0.1','6','IV rapid push','3','3 mg/mL. Must be given as rapid IV push followed immediately by 20 mL NS flush.','Causes transient asystole (3–10 sec) — warn patient. Second dose: 0.2 mg/kg (max 12 mg).','1','8'),
  ('Paracetamol IV','Fever / Pain','15','1000','IV infusion','10','10 mg/mL. Give over 15 min. Reduce dose in hepatic impairment.','Max 4 doses in 24h. Hepatotoxic in overdose.','1','9'),
  ('Oral Rehydration Salts','Dehydration / Diarrhoea',NULL,NULL,'Oral',NULL,'1 sachet in 1 litre boiled cooled water. Give 50–100 ml/kg over 4h for moderate dehydration.','For severe dehydration with vomiting: IV fluids first.','1','10');
INSERT OR IGNORE INTO osce_cards (condition_id,question,answer,station_type) VALUES
  ('dengue','Name 3 warning signs of dengue that require immediate hospital admission.','Any of: (1) Severe abdominal pain/tenderness, (2) Persistent vomiting >3 times/day, (3) Clinical fluid accumulation (ascites/effusion), (4) Mucosal bleeding, (5) Lethargy or restlessness, (6) Liver enlargement >2 cm, (7) Rapid drop in platelets with rising haematocrit.','history'),
  ('dengue','A 25-year-old with dengue shock (DSS) arrives. What is your immediate fluid management?','IV NS or Ringer''s Lactate 10–20 ml/kg over 1 hour. Reassess: if improved → step down to 5–7 ml/kg/hr. If not improved → repeat bolus. Max 2 boluses. If still no response → consider colloid (Dextran 40). Target: stable vitals, Hct stable, urine output >0.5 ml/kg/hr.','management'),
  ('dengue','A dengue patient''s Hct has risen from 38% to 46% in 12 hours. What does this mean and what do you do?','20% rise in Hct indicates significant plasma leakage (hallmark of Dengue Haemorrhagic Fever). Action: upgrade to Group B/C, increase IV fluid rate, monitor closely, check platelet count. Do NOT give diuretics.','data-interpretation'),
  ('dengue','Why is aspirin/ibuprofen contraindicated in dengue?','NSAIDs and aspirin inhibit platelet function and can precipitate or worsen bleeding in dengue. Paracetamol (max 4g/day) is the only safe antipyretic. Aspirin also risks Reye''s syndrome in children.','management'),
  ('typhoid','What is the most reliable diagnostic test for typhoid fever and when should it be collected?','Blood culture — gold standard. Should be collected in the first week of illness BEFORE antibiotics are started. Sensitivity 60–80%. Widal test is suggestive (O titre ≥1:160) but not diagnostic due to cross-reactivity.','history'),
  ('typhoid','What is the first-line antibiotic for uncomplicated typhoid in Bangladesh?','Azithromycin 1g stat then 500mg OD for 6 days (total 7-day course). Fluoroquinolones (ciprofloxacin) should be avoided due to high resistance in Bangladesh.','management'),
  ('pneumonia','What does the CURB-65 score assess and how does it guide management?','CURB-65 assesses CAP severity: Confusion, Urea >7, RR ≥30, BP <90/60, Age ≥65 (1 point each). Score 0–1: outpatient; Score 2: hospital admission; Score 3–5: consider ICU. Each point increases 30-day mortality.','data-interpretation'),
  ('pneumonia','What SpO2 target do you aim for in a patient with CAP without COPD?','SpO2 ≥94% on supplemental oxygen. In patients with known COPD or risk of hypercapnia, target 88–92% to avoid suppressing hypoxic respiratory drive.','management'),
  ('cholera','A 35-year-old with cholera has severe dehydration and is unable to sit up. What is your Plan C rehydration?','IV Ringer''s Lactate 100 ml/kg over 3 hours. First 30 ml/kg in 30 minutes. Reassess every 30 minutes. Once patient can drink, switch to ORS. Give single-dose Azithromycin 1g.','management');
INSERT OR IGNORE INTO lab_references (name,unit,normal_min,normal_max,critical_low,critical_high,notes) VALUES
  ('Haemoglobin (Male)','g/dL','13','17','7','20','<7 = severe anaemia, transfusion threshold'),
  ('Haemoglobin (Female)','g/dL','12','15','7','20','<7 = severe anaemia'),
  ('Haematocrit (Male)','%','39','50','20','60','>20% rise from baseline in dengue = plasma leakage'),
  ('Haematocrit (Female)','%','36','46','20','60',NULL),
  ('WBC (Total)','×10⁹/L','4','11','2','30','<4 leukopenia (typhoid, dengue); >11 infection/inflammation'),
  ('Platelet Count','×10⁹/L','150','400','20',NULL,'<100 = thrombocytopenia; <20 = transfusion risk; <10 = transfuse'),
  ('Serum Sodium','mmol/L','136','145','120','160','<120 or >160 = critical, treat urgently'),
  ('Serum Potassium','mmol/L','3.5','5','2.5','6.5','<2.5 = severe hypoK (arrhythmia risk); >6.5 = severe hyperK'),
  ('Serum Creatinine','µmol/L','60','110',NULL,'500','>500 = severe AKI'),
  ('Serum Urea','mmol/L','2.5','7',NULL,'30','>7 = CURB-65 point for pneumonia'),
  ('ALT (SGPT)','U/L','7','56',NULL,'1000','>1000 = severe hepatitis / dengue liver involvement'),
  ('AST (SGOT)','U/L','10','40',NULL,'1000','>1000 with dengue = Group C criteria'),
  ('Serum Bilirubin (Total)','µmol/L','5','17',NULL,'200','>200 = consider haemolysis or severe liver disease'),
  ('Blood Glucose (Fasting)','mmol/L','3.9','5.6','2.5','25','<2.5 = treat hypoglycaemia immediately; >25 = consider DKA'),
  ('SpO2','%','94','100','88',NULL,'<94 = supplemental O2; <88 = critical, high-flow O2 or NIV'),
  ('CRP','mg/L','0','5',NULL,'200','>100 = significant infection/inflammation'),
  ('Prothrombin Time (PT)','seconds','11','14',NULL,'30','>30 = significant coagulopathy, check INR'),
  ('INR','ratio','0.8','1.2',NULL,'3','>3.0 = bleeding risk; therapeutic range for anticoagulation 2–3');
COMMIT;